const CAT_NOMES: Record<string, string> = {
  tec: 'Tecnologia', sau: 'Saúde', eng: 'Engenharia', fin: 'Finanças',
  jur: 'Jurídico', edu: 'Educação', mkt: 'Marketing e Design', ges: 'Gestão e Administração',
  agr: 'Agronegócio', con: 'Construção e Arquitetura', log: 'Logística e Transporte',
  ven: 'Vendas e Comercial', out: 'Outros',
}

export const PROFISSOES: Profissao[] = RAW.map(r => ({
  slug: r[0], nome: r[1], cat: r[2], min: r[3], med: r[4], max: r[5],
  jr: r[6], pl: r[7], sr: r[8], form: r[9], mercado: r[10],
  futuro: r[11] ?? false, top: r[12] ?? false,
}))

export const CATEGORIAS_SALARIO = Object.entries(CAT_NOMES).map(([slug, nome]) => ({
  slug, nome, total: PROFISSOES.filter(p => p.cat === slug).length,
}))

export function getProfissaoBySlug(slug: string): Profissao | undefined {
  return PROFISSOES.find(p => p.slug === slug)
}

export function getProfissoesByCategoria(cat: string): Profissao[] {
  return PROFISSOES.filter(p => p.cat === cat)
}

export function getTopPagantes(n = 20): Profissao[] {
  return [...PROFISSOES].sort((a, b) => b.sr - a.sr).slice(0, n)
}

export function getProfissoesFuturo(): Profissao[] {
  return PROFISSOES.filter(p => p.futuro)
}

export function getSimilares(prof: Profissao, n = 4): Profissao[] {
  return PROFISSOES
    .filter(p => p.slug !== prof.slug && p.cat === prof.cat)
    .sort((a, b) => Math.abs(a.med - prof.med) - Math.abs(b.med - prof.med))
    .slice(0, n)
}

export function getCatNome(cat: string): string {
  return CAT_NOMES[cat] ?? cat
}
